;s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:57:\"\n		\n		\n		\n		\n		\n				\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"WordPress Playground Brings Speed, Stability, and Momentum\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://wordpress.org/news/2026/01/wordpress-playground-speed-stability-momentum/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 15 Jan 2026 16:53:33 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19673\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:399:\"WordPress Playground had a busy year in 2025, with updates that make it more capable for day-to-day development, plugin previews, and learning environments. The project’s latest year-in-review highlights progress across performance, compatibility, database support, and tooling, expanding what can be done in a WordPress environment that runs in the browser and through the command line. [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12643:\"\n<p class=\"wp-block-paragraph\">WordPress Playground had a busy year in 2025, with updates that make it more capable for day-to-day development, plugin previews, and learning environments. The project’s latest year-in-review highlights progress across performance, compatibility, database support, and tooling, expanding what can be done in a WordPress environment that runs in the browser and through the command line.</p>\n\n\n\n<p class=\"wp-block-paragraph\">From faster load times to broader plugin support, the throughline is clear: Playground is moving beyond quick demos and into workflows that help developers and educators test, iterate, and share WordPress experiences more easily.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-b1f71d27 wp-block-buttons-is-layout-flex\" style=\"border-style:none;border-width:0px;border-top-left-radius:0px;border-top-right-radius:0px;border-bottom-left-radius:0px;border-bottom-right-radius:0px\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-blue-5-background-color has-background wp-element-button\" href=\"https://wordpress.org/playground/\" style=\"border-top-left-radius:0px;border-top-right-radius:0px;border-bottom-left-radius:0px;border-bottom-right-radius:0px\">Try Playground Now</a></div>\n</div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"551\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm.png?resize=1024%2C551&#038;ssl=1\" alt=\"\" class=\"wp-image-19689\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm-scaled.png?resize=1024%2C551&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm-scaled.png?resize=300%2C161&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm-scaled.png?resize=768%2C413&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm-scaled.png?resize=1536%2C826&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.13.49-pm-scaled.png?resize=2048%2C1102&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<div style=\"height:30px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-group has-off-white-background-color has-background is-layout-constrained wp-container-core-group-is-layout-2033d2f1 wp-block-group-is-layout-constrained\" style=\"margin-top:0;margin-bottom:0;padding-top:var(--wp--preset--spacing--edge-space);padding-right:var(--wp--preset--spacing--edge-space);padding-bottom:var(--wp--preset--spacing--edge-space);padding-left:var(--wp--preset--spacing--edge-space)\">\n<p class=\"wp-block-paragraph\"><strong>Key Takeaways</strong></p>\n\n\n\n<div style=\"height:20px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Plugin previews are more reliable: </strong>99% of the top 1,000 plugins can be installed and activated successfully, making demos and evaluations more trustworthy.</li>\n\n\n\n<li><strong>Everything is faster:</strong> A performance upgrade reduced average response time by 42%, and further optimizations improved overall “time to first useful click.”</li>\n\n\n\n<li><strong>Database tools work in browser:</strong> Improved database compatibility enabled tools like phpMyAdmin to be used directly on <a href=\"https://playground.wordpress.net\">playground.wordpress.net</a>.<br><strong>More practical tooling for real work:</strong> Testing configurations and previewing changes can happen in one place, without a complete local environment first.</li>\n\n\n\n<li><strong>New visual gallery of blueprints:</strong> A new <a href=\"https://wordpress.github.io/blueprints/\">visual gallery of blueprints</a> provides excellent starting points for various types of sites.</li>\n\n\n\n<li><strong>Global adoption:</strong> Playground was used 1.4 million times globally, with growing documentation translations and community contributions.</li>\n</ul>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Reliable Plugin Previews and Experimentation</h2>\n\n\n\n<p class=\"wp-block-paragraph\">A headline update from 2025 is the focus on compatibility. In testing with the top 1,000 plugins from the WordPress plugin directory, 99% installed and activated successfully. That matters because it raises confidence in what Playground is best known for: letting people try things quickly, without a complex setup, and with fewer surprises.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This highlighted that Playground is increasingly useful as a general-purpose PHP sandbox. Alongside WordPress, it can support standard PHP tools and projects, which makes it easier to explore how WordPress fits into broader development workflows and to share reproducible environments with others.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you try something new and unexpected in Playground, the update encourages you to share what you learn in the <a href=\"https://wordpress.slack.com/archives/playground\">#playground</a> Slack channel, so the community can build a clearer picture of what works well today and what is improving next.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Faster Load Times</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Speed was a central theme in 2025. A recent <a href=\"https://make.wordpress.org/playground/2025/12/03/wordpress-playground-2025-year-in-review/\">year-in-review report</a> revealed a 42% reduction in average response time, and this is not just a single change. A series of improvements make Playground feel quicker in the moments people notice most, such as loading WordPress, opening wp-admin, and switching between tasks.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Several behind-the-scenes updates were described in plain terms as “less waiting”: checks happen earlier, parts of the experience load in a smarter order, and more content is reused from cache, so repeat actions are snappier.</p>\n\n\n\n<p class=\"wp-block-paragraph\">For people using Playground to review a plugin, validate a bug fix, or teach a class, these improvements mean the same thing: faster feedback loops, with fewer pauses that break concentration.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Better Tooling and Compatibility</h2>\n\n\n\n<p class=\"wp-block-paragraph\">In 2025, Playground also became more “toolbox-like” in the browser. The update highlighted features that reduce context switching, such as editing files on the page, building and testing starter configurations (Blueprints) in a dedicated editor, and launching database tools such as phpMyAdmin and Adminer with a single click.</p>\n\n\n\n<p class=\"wp-block-paragraph\">On the database side, a significant compatibility upgrade was introduced to improve support for more complex database behavior. The practical outcome is that more WordPress sites and plugins behave as expected in Playground, and more developer tools can run inside the environment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Blueprints also advanced in ways that benefit both builders and sharers. The updates focus on making starter setups easier to create, browse, and reuse, especially when a demo requires content, media, or a specific configuration that should launch consistently.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the clearest ways to see that progress is the <a href=\"https://wordpress.github.io/blueprints/\"><strong>WordPress Blueprints Gallery</strong></a>, a community library of ready-to-launch WordPress environments. From practical “building block” examples (such as starting with a specific login role) to demos that automatically install themes and plugins, to richer setups that generate posts and featured images via WP-CLI, the gallery demonstrates how quickly an idea can become a fully functional site that you can browse and share.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Examples:</strong></p>\n\n\n\n<div class=\"wp-block-columns are-vertically-aligned-center has-dark-strokes-grey-background-color has-background is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\" style=\"border-width:12px\">\n<div class=\"wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"714\" height=\"828\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.51.02-pm.png?resize=714%2C828&#038;ssl=1\" alt=\"\" class=\"wp-image-19694\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.51.02-pm.png?w=714&amp;ssl=1 714w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.51.02-pm.png?resize=259%2C300&amp;ssl=1 259w\" sizes=\"auto, (max-width: 714px) 100vw, 714px\" /></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://playground.wordpress.net/?blueprint-url=https%3A%2F%2Fraw.githubusercontent.com%2Fwordpress%2Fblueprints%2Ftrunk%2Fblueprints%2Fstylish-press%2Fblueprint.json\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"714\" height=\"828\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.53.15-pm.png?resize=714%2C828&#038;ssl=1\" alt=\"\" class=\"wp-image-19698\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.53.15-pm.png?w=714&amp;ssl=1 714w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-2.53.15-pm.png?resize=259%2C300&amp;ssl=1 259w\" sizes=\"auto, (max-width: 714px) 100vw, 714px\" /></a></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-vertically-aligned-center is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><a href=\"https://playground.wordpress.net/?blueprint-url=https%3A%2F%2Fraw.githubusercontent.com%2Fwordpress%2Fblueprints%2Ftrunk%2Fblueprints%2Forganization-kentwood%2Fblueprint.json\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"714\" height=\"826\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-3.05.37-pm.png?resize=714%2C826&#038;ssl=1\" alt=\"\" class=\"wp-image-19704\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-3.05.37-pm.png?w=714&amp;ssl=1 714w, https://i0.wp.com/wordpress.org/news/files/2026/01/Screenshot-2026-01-09-at-3.05.37-pm.png?resize=259%2C300&amp;ssl=1 259w\" sizes=\"auto, (max-width: 714px) 100vw, 714px\" /></a></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\"><em>For anyone who wants to experience the power of WordPress without the setup, the gallery serves as a strong reminder of what Playground makes possible: shareable, repeatable site experiences that work the same way every time — ideal for demos, workshops, testing, and “try it now” links.&nbsp;</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">Clear adoption signals back all of this. The review reports 1.4 million uses globally, documentation translations in multiple languages, and growing integration across the plugin directory through Playground-powered previews. It also points to a steady increase in community contribution, from documentation and support to talks and real-world workflows built on top of Playground.<br><br>A huge thank you to everyone who tried Playground over the past year,&nbsp; whether you launched a quick demo, tested a change, taught a workshop, or helped make the documentation more accessible in your language. And if there’s anything that would make Playground even more helpful for your day-to-day work, the project actively welcomes ideas and feature requests via the WordPress Playground GitHub issues tracker.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Looking Ahead</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As we closed out 2025 and now look forward to 2026, we can see several forward-looking initiatives, including work on MySQL binary protocol support (to enhance broader compatibility with MySQL tools) and continued exploration of debugging enhancements, such as expanded XDebug access.</p>\n\n\n\n<p class=\"wp-block-paragraph\">For anyone who last tried Playground as a quick demo environment, 2025’s updates suggested a shift in direction: Playground is increasingly positioned as a practical layer for testing, teaching, previewing, and reviewing WordPress, both in the browser and in local workflows.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"19673\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:60:\"\n		\n		\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"2026 Global Partner Program Announcement\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"https://wordpress.org/news/2025/12/2026-global-partner-program/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Dec 2025 17:16:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19534\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:412:\"Become a driving force behind WordPress innovation by joining the Global Community Sponsorship Program: a comprehensive initiative that supports the events and people powering our open source mission. As a Global Sponsor, your organization gains meaningful visibility across the international WordPress ecosystem while helping to fund events that foster growth, collaboration, and community. Why Choose [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Harmony Romo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:11677:\"\n<p class=\"wp-block-paragraph\">Become a driving force behind WordPress innovation by joining the Global Community Sponsorship Program: a comprehensive initiative that supports the events and people powering our open source mission. As a Global Sponsor, your organization gains meaningful visibility across the international WordPress ecosystem while helping to fund events that foster growth, collaboration, and community.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"\" class=\"wp-image-19617\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/WordPress-Global-Partners-Program-2026-.jpg?w=1600&amp;ssl=1 1600w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Why Choose Global Sponsorship?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Instead of managing multiple individual sponsorships, this streamlined program consolidates your efforts into one efficient and impactful partnership.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Efficiency and Simplified Administration</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Skip the complexity of coordinating invoice payments with numerous volunteer teams. Our centralized approach saves time and resources. In 2026, sponsors will benefit from:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>A dedicated Slack channel for direct communication with the WordPress Community Support team and Community Program Managers</li>\n\n\n\n<li>Monthly updates listing upcoming WordPress events, their current planning stages, and scheduled dates</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Expanded Reach and Impact</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Your sponsorship amplifies your presence worldwide, ensuring consistent visibility across global WordPress community events.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Stability and Reliability</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Your commitment strengthens locally organized events by providing predictable funding that supports venues, logistics, and growth.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Flexible Branding Options</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Adapt across your portfolio—Global Sponsors can represent different brands at different events (subject to approval and advance notice).</p>\n\n\n\n<h3 class=\"wp-block-heading\">Program Benefits</h3>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td class=\"has-text-align-left\" data-align=\"left\"></td><td class=\"has-text-align-center\" data-align=\"center\"><strong>Global&nbsp;Leader</strong></td><td class=\"has-text-align-center\" data-align=\"center\"><strong>Regional Powerhouse</strong></td><td class=\"has-text-align-center\" data-align=\"center\"><strong>Community Builder</strong></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\"><br><br><br><br><strong>Best for:<br></strong></td><td class=\"has-text-align-center\" data-align=\"center\">Established brands seeking global reach and year-round visibility.</td><td class=\"has-text-align-center\" data-align=\"center\">Companies aiming for regional dominance and strong brand recognition.</td><td class=\"has-text-align-center\" data-align=\"center\">Organizations supporting the next generation of WordPress education.</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Sponsorship payable in full or through quarterly installments</td><td class=\"has-text-align-center\" data-align=\"center\">$180,000</td><td class=\"has-text-align-center\" data-align=\"center\">$110,000</td><td class=\"has-text-align-center\" data-align=\"center\">$60,000</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Top tier sponsorship benefits at all local <a href=\"https://central.wordcamp.org/\">WordCamp</a> events (excludes flagships) with priority access to claim a sponsor table at in-person <a href=\"https://events.wordpress.org/\">WordPress events</a></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"></td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Option to feature multiple brands across events</td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"></td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Dedicated sponsor landing page</td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Complimentary WordPress event tickets for your team</td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Recognition across all <a href=\"https://events.wordpress.org/\">WordPress events</a></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Sponsor Spotlight post on WordPress.org/news featuring highlights from recent <a href=\"https://central.wordcamp.org/\">WordCamps</a></td><td class=\"has-text-align-center\" data-align=\"center\">Quarterly</td><td class=\"has-text-align-center\" data-align=\"center\">Annually</td><td class=\"has-text-align-center\" data-align=\"center\"></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Inclusion of your company logo in signage and materials for <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a> events</td><td class=\"has-text-align-center\" data-align=\"center\">All signage &amp; materials for the year (digital and printed)</td><td class=\"has-text-align-center\" data-align=\"center\">Signage &amp; materials for 5 events per year (printed only)</td><td class=\"has-text-align-center\" data-align=\"center\">All signage &amp; materials for the year (digital and printed)</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Opportunity to be featured in an exclusive digital binder for <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a> event organizers</td><td class=\"has-text-align-center\" data-align=\"center\">Priority placement (logos &amp; text)</td><td class=\"has-text-align-center\" data-align=\"center\">Feature listing (text only)</td><td class=\"has-text-align-center\" data-align=\"center\">Feature listing (text only)</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\">Regular recognition in <a href=\"https://make.wordpress.org/community/2025/11/03/monthly-education-buzz-report-october-2025/\">monthly education buzz report</a></td><td class=\"has-text-align-center\" data-align=\"center\"></td><td class=\"has-text-align-center\" data-align=\"center\"></td><td class=\"has-text-align-center\" data-align=\"center\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2714.png\" alt=\"✔\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></td></tr></tbody></table></figure>\n\n\n\n<h2 class=\"wp-block-heading\">How Sponsorship Funds Are Used</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Global Sponsorship funds directly support:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Local WordPress events worldwide (venue rental, catering, A/V, and more)</li>\n\n\n\n<li>Meetup.com license fees for over 671 WordPress Meetup groups globally</li>\n\n\n\n<li>Administrative costs like insurance, banking, and annual financial audits that ensure transparent operations</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Your partnership helps sustain the community that powers more than 43% of the web. Together, we can keep the WordPress project thriving and expanding for years to come.</p>\n\n\n\n<div class=\"wp-block-group has-off-white-2-background-color has-background is-layout-constrained wp-container-core-group-is-layout-2431c55b wp-block-group-is-layout-constrained\" style=\"padding-top:var(--wp--preset--spacing--edge-space);padding-right:var(--wp--preset--spacing--edge-space);padding-bottom:var(--wp--preset--spacing--edge-space);padding-left:var(--wp--preset--spacing--edge-space)\">\n<p class=\"has-text-align-center wp-block-paragraph\"><strong><strong>If your company is interested in joining the Global Sponsorship program or you would like to know more, please reach out</strong></strong>.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-3e41869c wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"mailto:support@wordcamp.org\">Contact WordPress Community Support</a></div>\n</div>\n\n\n\n<div style=\"height:25px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Please see&nbsp;<a href=\"https://make.wordpress.org/community/handbook/wordcamp-organizer/planning-details/fundraising/global-community-sponsorship-for-event-organizers/#rules-for-sponsor-materials\">Rules for Sponsor Materials</a>&nbsp;for more details about terms of sponsorship. Please also see our&nbsp;<a href=\"https://make.wordpress.org/community/files/2024/12/Draft-of-2025-WordPress-Global-Community-Sponsorship-Agreement-Template-Google-Docs.pdf\" target=\"_blank\" rel=\"noreferrer noopener\">sample sponsorship agreement</a>.</em></p>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">If you’d like to go one step further, please consider <a href=\"https://wordpressfoundation.org/donate/\">donating directly to the WordPress Foundation</a>. We operate lean—every dollar goes toward keeping WordPress free, supporting education, and funding the community that makes the web a better place. In short, your donation helps us keep the lights on and the mission alive.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"19534\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:65:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n\n\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:54:\"State of the Word 2025: Innovation Shaped by Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:45:\"https://wordpress.org/news/2025/12/sotw-2025/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 03 Dec 2025 18:26:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:9:\"Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:17:\"state of the word\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19447\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:354:\"State of the Word 2025 brought the WordPress community together for an afternoon that felt both reflective and forward-moving, blending stories of global growth with technical milestones and glimpses of the future. This year also marked the twentieth State of the Word since the first address in 2006, a milestone noted in the WordPress history [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:9:\"enclosure\";a:2:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:59:\"https://wordpress.org/news/files/2025/12/Telex-demo-776.mp4\";s:6:\"length\";s:8:\"29136831\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:3:\"url\";s:53:\"https://wordpress.org/news/files/2025/12/wapu-513.mp4\";s:6:\"length\";s:9:\"102323371\";s:4:\"type\";s:9:\"video/mp4\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Nicholas Garofalo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:38068:\"\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/U_DF4-23C8Q?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">State of the Word 2025 brought the WordPress community together for an afternoon that felt both reflective and forward-moving, blending stories of global growth with technical milestones and glimpses of the future. This year also marked the twentieth State of the Word since the first address in 2006, a milestone noted in the WordPress history book <a href=\"https://wordpress.org/book/2015/11/wordcamp-2006/\"><em>Milestones: The Story of WordPress</em></a> as the beginning of a tradition that has helped the project tell its own story.</p>\n\n\n\n<p class=\"wp-block-paragraph\">From the outset, the keynote carried a sense of momentum shaped by thousands of contributors, educators, students, and creators whose steady participation continues to define the open web. It was a reminder that WordPress is more than software. It is a community writing its future together.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">What we have is more than code. It’s momentum, it’s culture, and it’s a system that lets people learn by doing and lead by showing up.  — <a href=\"https://profiles.wordpress.org/4thhubbard/\">Mary Hubbard</a>, WordPress Executive Director</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Mary opened the evening by reflecting on her first full year as Executive Director, a year spent listening deeply and seeing firsthand how people across regions learn, contribute, and lead. Her remarks grounded the keynote in the lived reality of a community that grows because people invest in one another, teach openly, and build trust through contribution.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">I’ve met people using WordPress to unlock new careers. I’ve met contributors who started a single translation or forum post and are now leading major pieces of the project. In LatAm, Europe, and the States, I’ve seen students get access to WordPress tools and start building faster than we could have ever imagined. I’ve watched communities build in public, resolve disagreements in the open, and collaborate across languages and time zones.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">That reflection offered a clear reminder of what makes WordPress resilient through change: a culture of showing up, learning by doing, and supporting others along the way. The project moves forward because people choose to participate in ways both large and small, strengthening the foundation that has carried WordPress for more than two decades.</p>\n\n\n\n<p class=\"wp-block-paragraph\">With that foundation in place, the keynote moved through a series of stories and demonstrations that highlighted where WordPress stands today and where it is headed next — from a historic live release of WordPress 6.9 to expanding global education pathways, emerging AI capabilities, and deeper collaboration across the entire ecosystem.</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress by the Numbers</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Project Cofounder <a href=\"https://profiles.wordpress.org/matt/\">Matt Mullenweg</a> began with a wide-angle view of the project’s growth. WordPress powers over 43% of the web, with 60.5% of the CMS market. Shopify, its nearest competitor, holds 6.8%. Among the top 1,000 websites, WordPress’s share climbed to 49.4%, up 2.3% from the previous year.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"Globe graphic noting 43% of websites and 60.5% CMS market share\" class=\"wp-image-19500\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-43-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Multilingual usage continued its strong rise. Over 56% of WordPress sites now run in languages other than English. Japan stood out, with WordPress powering 58.5% of all Japanese websites and 83% of the CMS market. Japanese became the second most-used language on WordPress at 5.82%. Spanish followed, then German, French, and Brazilian Portuguese.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The plugin ecosystem saw explosive growth. The directory surpassed 60,000 plugins, and plugin downloads were on pace to reach 2.1 billion by year-end. Over 1,500 themes have been released this year as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Contributors also hit new highs. The 6.8 release included 921 contributors, the largest group yet. WordPress 6.8 saw 79.5 million downloads, up 13%, and WordPress 6.9 included contributions from 230 first-time contributors and more than 340 enhancements and fixes.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A Release Moment to Remember</h2>\n\n\n\n<p class=\"wp-block-paragraph\">This year’s keynote delivered something WordPress had never attempted before: a live on-stage release of <a href=\"https://wordpress.org/download/releases/6-9/\">WordPress 6.9</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"WordPress 6.9 Gene album cover art\" class=\"wp-image-19511\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-gene-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Mary set the moment up earlier in the program, calling WordPress 6.9 “fast, polished, and built for collaboration.” She explained that it reflected a year of intentional iteration, improved workflows, and deeper cross-team participation.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Matt took the stage with some of the release leads, the release button in hand. The room counted down, and then WordPress 6.9 shipped live, instantly updating millions of sites around the world. It was both a celebration and a testament to the reliability and trust the WordPress community has built into its release processes. Shipping a major version of WordPress in real time, on stage, without drama, is something the early contributors could hardly have imagined.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"Photo of WordPress release leads pressing the button to release 6.9\" class=\"wp-image-19457\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/release-leads-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">That reflection connected back to WordPress’s origin story. Matt talked about discovering the <a href=\"https://en.wikipedia.org/wiki/WordPress#History\">B2</a> forums, asking questions, and eventually reaching the point where he could answer someone else’s. That transition from learner to contributor remains at the heart of the project today. Two decades later, WordPress has grown from those early interactions into a platform that can ship a major release in front of the world, powered by thousands of contributors building together.</p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress and the Future of AI</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As the keynote shifted toward the future, Matt acknowledged what has become an essential truth of the moment: it would be impossible to talk about the next chapter of WordPress without talking about AI. He reminded the audience that in 2022, long before ChatGPT entered global conversation, he encouraged the community to “learn AI deeply.” The speed of change since then, he said, has exceeded every expectation, and WordPress has been preparing for it in ways both visible and behind the scenes.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"Timeline of AI: 2022 ChatGPT launches, 2023 GPT-4 and Claude launches, 2024 Multimodel and video generation, 2025 AI everywhere\" class=\"wp-image-19510\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-AI-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Matt introduced one of the most important architectural developments of the year: the Abilities API and the MCP adapter. The Abilities API defines what WordPress can do in a structured way that AI systems can interpret, while the MCP adapter exposes those abilities through a shared protocol. This means AI agents — whether built by individuals, companies, or larger platforms — can understand and interact with WordPress safely and predictably. Instead of relying on one-off integrations or brittle interfaces, WordPress now participates in a broader ecosystem of tools that can query its capabilities and perform tasks using a standard, governed approach.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Matt then highlighted how developers are already using AI in their everyday work through tools like Cursor, Claude Code, and next-generation CLIs. These tools can explore entire codebases, generate documentation, produce tests, refactor large components, and even coordinate sequences of WP-CLI commands. For many developers, they expand what a single person can accomplish in an afternoon. They don’t eliminate the need for human judgment — they amplify it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">With that foundation laid, Matt turned the audience’s attention to <a href=\"https://telex.automattic.ai/\">Telex</a>, the experimental environment designed to turn natural-language prompts into Gutenberg Blocks. Telex has already moved beyond experimentation and into real use. Matt showed examples from community creator Nick Hamze, who uses Telex to power micro-business tools that represent practical, revenue-generating workflows that previously required custom engineering.</p>\n\n\n\n<figure class=\"wp-block-video\"><video height=\"2160\" style=\"aspect-ratio: 3840 / 2160;\" width=\"3840\" controls src=\"https://wordpress.org/news/files/2025/12/Telex-demo-776.mp4\"></video></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Matt then widened the lens to show what companies across the ecosystem are building with AI. Hostinger’s Kodee can generate a complete WordPress site from a single description. Elementor AI demonstrated similarly rapid creation inside its own editor, producing full sections and layouts in seconds. WordPress.com showcased how its AI tools help users draft, rewrite, and refine content while keeping language aligned with the site’s voice. Yoast demonstrated how AI can support SEO workflows by generating structured suggestions and improving readability. Together, these examples illustrated that AI is not arriving in one place — it is arriving everywhere.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Experimental browsers can navigate WP Admin autonomously, performing tasks such as clicking buttons, opening menus, changing settings, and performing multi-step tasks without requiring any custom plugins or APIs. This raised a key question that Matt encouraged the community to consider: Which AI capabilities should live inside WordPress itself, and which should remain external, operating through the browser or operating system?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Matt closed the section by discussing WordPress-specific AI benchmarks and evaluation suites. These shared tests will measure how well AI systems understand and execute WordPress tasks, from enabling plugins to navigating WP Admin to modifying content and settings. The goal is to create a foundation where future AI tools behave predictably and responsibly across the entire ecosystem, giving creators confidence that intelligent tools understand the platform deeply.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A Global Community Growing Together</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Mary then returned to the stage to celebrate the ecosystem that supports WordPress&#8217;s growth. Across continents, diverse groups of people have hosted WordPress events, training new contributors and welcoming newcomers into the project. WordCamp growth in 2025 reflected that: more than 81 WordCamps across 39 countries, powered by over 5,000 volunteers and attended by nearly 100,000 people, with sixteen more events still underway.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"\" class=\"wp-image-19503\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wordcamps-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Education played a major role in this community expansion. Learn.WordPress.org served over 1.5 million learners this year, with clearer pathways into more structured programs like <a href=\"https://wordpress.org/education/campus-connect/\">Campus Connect</a> and <a href=\"https://wordpress.org/education/credits/\">WordPress Credits</a>. This bridging was deliberate. Many learners arrive through tutorials or workshops but need clearer guidance on how to deepen their skills. By reshaping navigation and improving wayfinding across WordPress.org, the project began closing that gap.</p>\n\n\n\n<p class=\"wp-block-paragraph\">She spotlighted <a href=\"https://make.wordpress.org/community/2025/09/29/wordpress-and-higher-education-an-alliance-that-transforms/\">Costa Rica’s Universidad Fidélitas</a>, where WordPress moved beyond extracurricular interest into formal academic integration. Long before signing an agreement with the WordPress Foundation, their students were hosting WordCamp San José, forming student clubs, and treating WordPress as a crucial part of digital literacy and professional development.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"\" class=\"wp-image-19505\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-photo-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\">Students of the WordPress Fidélitas Club</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Wapuu appeared across events as a familiar companion and a cultural thread running through contributor tools and community projects. Its presence was a reminder that creativity and playfulness are as essential to open source as documentation or code.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"Various Wapuu artwork examples\" class=\"wp-image-19506\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-wapuu-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Matt highlighted the story of <a href=\"https://events.wordpress.org/managua/2025/wordpress-youth-day/\">Youth Day in Managua, Nicaragua</a>. Seventy-five young people spent a full day building their first WordPress sites. Sessions were taught by teenagers, for teenagers. They learned to pick themes, customize layouts, create contact forms, and publish content. Contribution often starts with a simple moment of confidence, and those early sparks can shape entire careers.</p>\n\n\n\n<figure class=\"wp-block-video\"><video height=\"2160\" style=\"aspect-ratio: 3840 / 2160;\" width=\"3840\" controls src=\"https://wordpress.org/news/files/2025/12/wapu-513.mp4\"></video></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Together, these moments illustrated a project expanding not just in numbers, but in depth, diversity, and global reach. WordPress is growing because communities are finding their own ways to embrace it.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What’s New in WordPress 6.9</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Joining virtually, WordPress Lead Architect, <a href=\"https://profiles.wordpress.org/matveb/\">Matías Ventura</a>, shifted the keynote from vision to practice. Matías offered a detailed walkthrough of what makes WordPress 6.9 one of the most refined, collaborative, and forward-looking releases the project has shipped in years. He returned to the four familiar lenses of creation — writing, designing, building, and developing — and showed how each evolved in this release cycle.</p>\n\n\n\n<p class=\"wp-block-paragraph\">He began with notes in the Block Editor, one of the most anticipated features. Notes allow collaborators to comment directly on individual blocks in a post or page. When a note is selected, the surrounding content subtly fades, helping contributors stay focused on context. Because notes are built on WordPress’s native comment system, they integrate seamlessly with existing communication workflows, including email notifications. Matías highlighted that notes development exemplified collaboration at its best, with contributors from various companies working together to bring the feature to life.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" class=\"youtube-player\" width=\"600\" height=\"338\" src=\"https://www.youtube.com/embed/vkYulcN0lbc?version=3&#038;rel=1&#038;showsearch=0&#038;showinfo=1&#038;iv_load_policy=1&#038;fs=1&#038;hl=en-US&#038;autohide=2&#038;wmode=transparent\" allowfullscreen=\"true\" style=\"border:0;\" sandbox=\"allow-scripts allow-same-origin allow-popups allow-presentation allow-popups-to-escape-sandbox\"></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">From there, he turned to refinements across the writing and design experience. Editor interactions feel smoother and more consistent. Patterns behave more predictably. Spacing and typography controls are clearer, more organized, and more intuitive. Together these capabilioties make the experience of writing and designing inside WordPress calmer, more reliable, and more empowering.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Block bindings now provide a more intuitive, visual way to connect blocks to dynamic data sources. Users can switch or remove bindings with a single click, and developers can register additional sources to support custom workflows. This work lays the foundation for a future where dynamic data flows more naturally through blocks, enabling site creators to build richer interfaces without writing code.</p>\n\n\n\n<p class=\"wp-block-paragraph\">On the developer front, Matías focused on three foundational upgrades that represent major steps forward in how WordPress will evolve over the coming years.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>The first was the <strong>Abilities API</strong>, a unified registry that describes what WordPress can do — across PHP, REST endpoints, the command palette, and future AI-driven interactions.</li>\n\n\n\n<li>The <strong>HTML API</strong> introduces new ways of working with and modifying HTML server-side. The API ensures safer, more reliable handling, lowering the barrier for theme and block developers who work with dynamic or structured markup.</li>\n\n\n\n<li>The <strong>Interactivity API</strong> delivers smoother, faster interactions without requiring heavy JavaScript frameworks. Improved routing, better state management, and clearer conventions help developers create rich, modern interfaces without leaving the WordPress philosophy of simplicity and flexibility.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">After Matías wrapped his presentation, Matt stepped back in to highlight several developments that build on the foundations of 6.9 and strengthen the overall WordPress ecosystem. He pointed first to the <a href=\"https://wordpress.org/plugins/plugin-check/\">Plugin Check Plugin</a>, a tool designed to help developers align with current WordPress standards and catch common issues early, making plugins more reliable for users and easier to maintain over time. Matt then spoke about ongoing progress in <a href=\"https://wordpress.org/data-liberation/\">Data Liberation</a>, noting improvements to the <a href=\"https://wordpress.org/plugins/wordpress-importer/\">WordPress importer</a> that make it easier for people to bring their content into WordPress without disruption or loss, an important step toward ensuring the open web remains portable and resilient. He also highlighted advances across the <a href=\"https://playground.wordpress.net/\">Playground</a> ecosystem, including <a href=\"https://developer.wordpress.com/studio/\">WordPress Studio</a>, the Playground CLI, and an expanding set of Blueprints. These allow developers and learners to spin up complete WordPress environments in seconds, test ideas, and experiment without servers or configuration. Matt closed this portion by emphasizing work on safer updates, which help WordPress avoid partial installs and ensure that updates complete smoothly even in less predictable hosting conditions, reinforcing WordPress’s commitment to stability as the platform continues to grow.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Matt emphasized that WordPress 6.9 is not defined by any single headline feature, but by a broad spectrum of refinements across the entire experience. It is a release that deepens reliability, expands capability, and sets the stage for future innovation.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Insights from the AI Panel</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The keynote transitioned into a live AI panel moderated by Mary Hubbard. The panel brought together four perspectives from across the ecosystem: <a href=\"https://profiles.wordpress.org/isotropic/\">James LePage</a> (Automattic), <a href=\"https://profiles.wordpress.org/flixos90/\">Felix Arntz</a> (Google), and <a href=\"https://profiles.wordpress.org/jeffpaul/\">Jeff Paul</a> (Fueled, FKA 10up), and Matt Mullenweg. Their conversation touched on the philosophy, practice, and future of AI inside WordPress — not as a distant trend, but as an active part of the project’s evolution.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A central theme was AI’s ability to amplify human creativity. James LePage put it plainly:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">It’s not that we’re going to just add sparkle buttons everywhere. We’re going to do some crazy stuff here — things we’re going to build into the way you interact with creating content, with expressing yourself digitally. We want to give you more power, more control, and make you more effective at creating.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Jeff Paul echoed this sentiment, emphasizing that AI should make developers more productive by handling repetitive work and freeing them to focus on higher-level decisions. Felix Arntz expanded the idea further, describing how Google sees AI as a way to make the web more accessible and intuitive, especially for new creators who may not have formal technical training.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"572\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/panel.jpg?resize=1024%2C572&#038;ssl=1\" alt=\"\" class=\"wp-image-19462\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/panel-scaled.jpg?resize=1024%2C572&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/panel-scaled.jpg?resize=300%2C168&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/panel-scaled.jpg?resize=768%2C429&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/panel-scaled.jpg?resize=1536%2C858&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/panel-scaled.jpg?resize=2048%2C1144&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\">From left to right: Mary Hubbard, Matt Mullenweg, Jeff Paul, Felix Arntz, James LePage</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Looking ahead, the panelists predicted deeper contextual integrations, AI-assisted debugging and scaffolding for developers, and workflows where agents can take on sequences of tasks while remaining directed by human decisions. They also highlighted the importance of standards, shared protocols, and privacy-focused design as essential components of WordPress’s long-term approach.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">The next 20 years looks like WordPress remaining what it is today, which is the center of the open web.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">The panel closed on a forward-looking but steady note. AI is accelerating, but WordPress is designing its foundations with flexibility and values that endure. The tools may change, but the commitment to openness, agency, and creative freedom remains the compass.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Questions That Push Us Forward</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Matt introduced the Q&amp;A as one of his favorite parts of State of the Word because it reveals what people are imagining, struggling with, or eager to build.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA.jpg?resize=1024%2C576&#038;ssl=1\" alt=\"Q&amp;A\" class=\"wp-image-19512\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA-scaled.jpg?resize=1024%2C576&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA-scaled.jpg?resize=300%2C169&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA-scaled.jpg?resize=768%2C432&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA-scaled.jpg?resize=1536%2C864&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/12/State-of-the-Word-2025-QandA-scaled.jpg?resize=2048%2C1152&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">The first question addressed the growing interconnectedness of today’s web. What happens, a participant asked, when a major provider like Cloudflare goes down? As tools and agents rely more heavily on external services, failures can cascade. Matt acknowledged that outages are increasingly visible, but also argued that each one strengthens the system.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">&#8220;Every failure, every edge case, everything that you never imagined is just another opportunity to find that new edge case,” he said. Resilience is not avoidance of failure, but the ability to grow stronger after it.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Another question focused on the longevity of web content. With platforms shutting down or links breaking over time, how can creators ensure their work endures? Matt pointed to the Internet Archive as one of the great stabilizers of the open web. He highlighted a <a href=\"https://wordpress.org/plugins/internet-archive-wayback-machine-link-fixer/\">new plugin</a> that automatically scans posts and replaces dead links with archived versions, helping preserve the historical fabric of the web even as individual services come and go.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The next question turned to real-time collaboration inside WordPress. A participant asked how co-editing fits into the future of WordPress and how these tools might help creators work more confidently. Matt talked about how collaboration tools can support people who are just starting their creative journeys — whether they are entrepreneurs, students, or first-time site builders. He described real-time editing as part of a broader vision of WordPress “just doing the work for you” in high-pressure or early-stage creative moments.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The final question considered long-term decision-making. Matt noted that predicting what will change is difficult, but identifying what will remain the same is much easier. For WordPress, he said, the invariant is clear: people will always want agency, openness, and the ability to publish on their own terms. These values guide decisions not only in the present, but across decades of future evolution.</p>\n\n\n\n<h2 class=\"wp-block-heading\">TBPN Podcast Appearance</h2>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"&#x1f534; CODE RED &#x1f534;, Dell Donates Size, Bun Acquired, AWS CEO Joins, Tae Kim Tells All\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/eBQh57HuJzk?start=10036&#038;feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<p class=\"wp-block-paragraph\">After the Q&amp;A, the keynote shifted gears with a live crossover segment featuring TBPN (the Technology Business Programming Network), a tech-focused podcast. The segment introduced a lively, unscripted energy into the room.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The hosts kicked things off by asking Matt what the “word of the year” should be. He chose “freedom”, connecting it directly to the core philosophy of open source. He described open source licenses as a kind of “bill of rights for software,” giving users inalienable rights that no company can revoke. In a world increasingly shaped by software platforms and digital ecosystems, these freedoms form the heart of what keeps the web open and accessible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Conversation then moved to <a href=\"https://www.beeper.com/\">Beeper</a>, the multi-network messaging client. Asked whether Beeper aims to “tear down walled gardens,” Matt rejected that framing. Instead, he offered a more collaborative metaphor: bringing gardens together. Most people have friends and colleagues scattered across WhatsApp, Instagram, LinkedIn, Messenger, and SMS. Beeper doesn’t replace those apps — it brings messages together into a unified interface..</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation eventually returned to publishing. Matt referenced the same principle he noted earlier: the importance of identifying what won’t change. For WordPress, he said, that means doubling down on freedom, agency, and the ability to publish without gatekeepers. Even as AI evolves, even as platforms shift, even as new tools emerge, these are the values that will guide the project forward.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Building the Web We Believe In</h2>\n\n\n\n<p class=\"wp-block-paragraph\">As the keynote drew to a close, Matt returned to a message that had threaded through every section of the evening. The future of WordPress is not arriving from outside forces — it is being crafted, questioned, tested, and expanded by the people who show up. Contributors, students, educators, community organizers, designers, developers, business owners, and first-time site builders all play a role in shaping the platform.</p>\n\n\n\n<p class=\"wp-block-paragraph\">He spoke about the opportunities ahead: new tools that expand what creators can build, collaborative features that make teamwork feel natural, and AI systems that enhance creativity rather than diminish it. Across continents, generations, and skill levels, people are discovering WordPress as a path to learning, empowerment, and expression.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The values that brought the project this far remain the ones that will carry it forward: freedom, participation, learning, and community. These aren’t abstract principles. They are lived every day in the decisions contributors make, the ideas they pursue, and the care they bring to the work.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Future Events</h3>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re feeling inspired to revisit past moments from the project’s annual address, the <a href=\"https://www.youtube.com/playlist?list=PL1pJFUVKQ7ES1piZxljCvMTJCYpVBnwYU\">State of the Word YouTube playlist</a> offers a look back at years of community milestones and product progress. The excitement continues into 2026, with major WordPress events already on the horizon: <a href=\"https://asia.wordcamp.org/2026/\">WordCamp Asia</a> in Mumbai, India,<a href=\"https://europe.wordcamp.org/2026/\">WordCamp Europe</a> in Kraków, Poland, and <a href=\"https://us.wordcamp.org/2026/\">WordCamp US</a> in Phoenix. We hope to see you there as the community continues building what comes next.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"19447\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:32:\"https://wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"14607090\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:12:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Mon, 02 Mar 2026 11:57:58 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:25:\"strict-transport-security\";s:12:\"max-age=3600\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Fri, 27 Feb 2026 02:20:55 GMT\";s:4:\"link\";s:63:\"<https://wordpress.org/news/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:2:\"br\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}s:5:\"build\";i:1760643936;s:21:\"cache_expiration_time\";i:1772495878;s:23:\"__cache_expiration_time\";i:1772495878;}','off'),(1232,'_site_transient_timeout_feed_mod_71a7765c3d553e44aaa308159b5a2ba6','1772495878','off'),(1233,'_site_transient_feed_mod_71a7765c3d553e44aaa308159b5a2ba6','1772452678','off'),(1234,'_site_transient_timeout_wp_remote_block_patterns_80c580d884c10bb52d577c550ae0e9a5','1772456291','off');
INSERT INTO `wp_options` VALUES (1235,'_site_transient_wp_remote_block_patterns_80c580d884c10bb52d577c550ae0e9a5','a:94:{i:0;O:8:\"stdClass\":7:{s:2:\"id\";i:515135;s:5:\"title\";O:8:\"stdClass\":1:{s:8:\"rendered\";s:50:\"Área de introducción con encabezamiento e imagen\";}s:7:\"content\";O:8:\"stdClass\":2:{s:8:\"rendered\";s:1746:\"\n<div class=\"wp-block-group alignfull is-content-justification-center is-layout-constrained wp-block-group-is-layout-constrained\" style=\"margin-top:0;margin-bottom:0\">\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-group alignwide is-layout-flow wp-block-group-is-layout-flow\">\n<div class=\"wp-block-columns alignwide are-vertically-aligned-top is-layout-flex wp-container-core-columns-is-layout-f40d6e23 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-vertically-aligned-top is-content-justification-left is-layout-constrained wp-container-core-column-is-layout-b7e24cf4 wp-block-column-is-layout-constrained\">\n<h2 class=\"wp-block-heading\">Descubre un reino de oportunidades.</h2>\n</div>\n\n\n\n<div class=\"wp-block-column is-vertically-aligned-top is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:40%\">\n<p class=\"wp-block-paragraph\">Explorando el complejo tapiz de la vida, las opciones revelan rutas hacia lo excepcional, requiriendo innovación, curiosidad y valentía para un viaje profundamente satisfactorio.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Primeros pasos</a></div>\n</div>\n</div>\n</div>\n\n\n\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img decoding=\"async\" src=\"https://pd.w.org/2023/07/44364b18862589f06.53436652.jpg\" alt=\"\" style=\"aspect-ratio:16/9;object-fit:cover\" /></figure>\n</div>\n\n\n\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n</div>\n\";s:9:\"protected\";b:0;}s:4:\"meta\";O:8:\"stdClass\":10:{s:14:\"_crdt_document\";s:0:\"\";s:31:\"jetpack_post_was_ever_published\";b:0;s:13:\"wpop_keywords\";s:28:\"Sección a pantalla completa\";s:16:\"wpop_description\";s:112:\"Dos columnas de texto, la izquierda con un encabezado y la derecha con un párrafo, con una imagen amplia abajo.\";s:19:\"wpop_viewport_width\";i:1200;s:16:\"wpop_block_types\";a:1:{i:0;s:0:\"\";}s:11:\"wpop_locale\";s:5:\"es_ES\";s:15:\"wpop_wp_version\";s:3:\"6.5\";s:25:\"wpop_contains_block_types\";s:111:\"core/button,core/buttons,core/column,core/columns,core/group,core/heading,core/image,core/paragraph,core/spacer\";s:9:\"footnotes\";s:0:\"\";}s:14:\"category_slugs\";a:1:{i:0;s:5:\"about\";}s:13:\"keyword_slugs\";a:1:{i:0;s:4:\"core\";}s:15:\"pattern_content\";s:2448:\"<!-- wp:group {\"metadata\":{\"name\":\"Intro\"},\"align\":\"full\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"className\":\"alignfull\",\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-group alignfull\" style=\"margin-top:0;margin-bottom:0\"><!-- wp:spacer {\"height\":\"var:preset|spacing|20\"} -->\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:group {\"metadata\":{\"name\":\"Contents\"},\"align\":\"wide\",\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"align\":\"wide\",\"style\":{\"spacing\":{\"blockGap\":{\"top\":\"var:preset|spacing|30\"}}}} -->\n<div class=\"wp-block-columns alignwide are-vertically-aligned-top\"><!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"\",\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\",\"contentSize\":\"450px\"}} -->\n<div class=\"wp-block-column is-vertically-aligned-top\"><!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Descubre un reino de oportunidades.</h2>\n<!-- /wp:heading --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"40%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:40%\"><!-- wp:paragraph -->\n<p>Explorando el complejo tapiz de la vida, las opciones revelan rutas hacia lo excepcional, requiriendo innovación, curiosidad y valentía para un viaje profundamente satisfactorio.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">Primeros pasos</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:spacer {\"height\":\"var:preset|spacing|20\"} -->\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:image {\"aspectRatio\":\"16/9\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"https://pd.w.org/2023/07/44364b18862589f06.53436652.jpg\" alt=\"\" style=\"aspect-ratio:16/9;object-fit:cover\" /></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {\"height\":\"var:preset|spacing|20\"} -->\n<div style=\"height:var(--wp--preset--spacing--20)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer --></div>\n<!-- /wp:group -->\";}i:1;O:8:\"stdClass\":7:{s:2:\"id\";i:310653;s:5:\"title\";O:8:\"stdClass\":1:{s:8:\"rendered\";s:40:\"Cover Poster on Left, Paragraph on Right\";}s:7:\"content\";O:8:\"stdClass\":2:{s:8:\"rendered\";s:3959:\"\n<div class=\"wp-block-cover alignfull has-custom-content-position is-position-top-center\" style=\"margin-top:0;padding-top:5vw;padding-right:5vw;padding-bottom:5vw;padding-left:5vw\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-100 has-background-dim\" style=\"background-color:#36220c\"></span><div class=\"wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow\">\n<div class=\"wp-block-group is-content-justification-space-between is-layout-flex wp-container-core-group-is-layout-c73042ca wp-block-group-is-layout-flex\">\n<div class=\"wp-block-cover is-light has-custom-content-position is-position-top-right wp-container-content-ceb7f5b3 wp-duotone-rgb137750-rgb210210210-1\" style=\"padding-top:4vw;padding-right:4vw;padding-bottom:4vw;padding-left:4vw;min-height:75vh;aspect-ratio:unset;\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\"></span><img decoding=\"async\" class=\"wp-block-cover__image-background wp-image-334\" alt=\"\" src=\"https://pd.w.org/2023/04/654642d52f20d6367.57324872.jpg\" data-object-fit=\"cover\" /><div class=\"wp-block-cover__inner-container is-layout-flow wp-block-cover-is-layout-flow\">\n<div class=\"wp-block-group is-vertical is-content-justification-right is-nowrap is-layout-flex wp-container-core-group-is-layout-06b49a26 wp-block-group-is-layout-flex\">\n<p class=\"has-text-color wp-block-paragraph\" style=\"color:#e5683a;font-size:140px;font-style:normal;font-weight:800;letter-spacing:-6px;line-height:0.8;text-transform:uppercase\">Wardell</p>\n\n\n\n<p class=\"has-text-color wp-block-paragraph\" style=\"color:#e5683a;font-size:130px;font-style:normal;font-weight:800;letter-spacing:-6px;line-height:0.8;text-transform:uppercase\">gris</p>\n\n\n\n<p class=\"has-text-align-center has-text-color wp-block-paragraph\" style=\"color:#d09c9c;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:1;text-transform:uppercase\">Plays</p>\n\n\n\n<p class=\"has-text-align-center has-text-color wp-block-paragraph\" style=\"color:#e59937;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:0.8;text-transform:uppercase\">Bebop &amp;</p>\n\n\n\n<p class=\"has-text-align-center has-text-color wp-block-paragraph\" style=\"color:#e59937;font-size:90px;font-style:normal;font-weight:800;letter-spacing:0px;line-height:1;text-transform:uppercase\">SWING</p>\n</div>\n</div></div>\n\n\n\n<div class=\"wp-block-group wp-container-content-d387280b is-vertical is-nowrap is-layout-flex wp-container-core-group-is-layout-b27f8d4a wp-block-group-is-layout-flex\">\n<p class=\"has-text-color wp-block-paragraph\" style=\"color:#e59937;font-size:18px;font-style:normal;font-weight:400;letter-spacing:0px;line-height:1.7\">Wardell Gray nació en Oklahoma City, el menor de cuatro hermanos. Pasó los primeros años de su infancia en Oklahoma, antes de trasladarse con su familia a Detroit en 1929. </p>\n\n\n\n<p class=\"has-text-color wp-block-paragraph\" style=\"color:#e59937;font-size:18px;font-style:normal;font-weight:400;letter-spacing:0px;line-height:1.7\">A principios de 1935, Gray empezó a asistir al instituto Northeastern High School, y luego se trasladó al instituto Cass Technical High School, que destaca por tener como antiguos alumnos a Donald Byrd, Lucky Thompson y Al McKibbon. </p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-left is-nowrap is-layout-flex wp-container-core-buttons-is-layout-af480da9 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button has-custom-font-size is-style-outline is-style-outline--2\" style=\"font-size:16px;font-style:normal;font-weight:700;letter-spacing:0px;text-transform:uppercase\"><a class=\"wp-block-button__link has-text-color wp-element-button\" style=\"border-radius:0px;color:#e59937;padding-top:16px;padding-right:32px;padding-bottom:16px;padding-left:32px\">Escuchar ahora</a></div>\n</div>\n\n\n\n<div style=\"height:7.5vw\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n</div>\n</div>\n</div></div>\n\";s:9:\"protected\";b:0;}s:4:\"meta\";O:8:\"stdClass\":10:{s