inHeightUnit\":\"px\",\"customGradient\":\"linear-gradient(35deg,rgb(6,0,151) 0%,rgb(130,4,255) 73%,rgb(193,15,255) 100%)\",\"isDark\":false,\"align\":\"full\"} -->\n<div class=\"wp-block-cover alignfull is-light\" style=\"min-height:720px\"><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-100 has-background-dim has-background-gradient\" style=\"background:linear-gradient(35deg,rgb(6,0,151) 0%,rgb(130,4,255) 73%,rgb(193,15,255) 100%)\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:group {\"align\":\"wide\",\"layout\":{\"inherit\":true,\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignwide\"><!-- wp:media-text {\"align\":\"wide\",\"mediaPosition\":\"right\",\"mediaId\":193,\"mediaLink\":\"http://localhost:8888/inicio/libros-2/\",\"mediaType\":\"image\",\"mediaWidth\":43,\"verticalAlignment\":\"center\",\"imageFill\":false} -->\n<div class=\"wp-block-media-text alignwide has-media-on-the-right is-stacked-on-mobile is-vertically-aligned-center\" style=\"grid-template-columns:auto 43%\"><div class=\"wp-block-media-text__content\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":1,\"textColor\":\"white\"} -->\n<h1 class=\"wp-block-heading has-text-align-left has-white-color has-text-color\">Bienvenido a Editorial Morfeo!</h1>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"className\":\"has-white-color has-text-color\"} -->\n<p class=\"has-white-color has-text-color\">En <strong>Editorial Morfeo</strong> vivimos y respiramos literatura. Somos más que una editorial: somos un espacio donde las historias cobran vida, donde la creatividad no tiene límites y donde las tendencias del mundo editorial se encuentran con la pasión por contar historias únicas.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-white-color has-text-color\"} -->\n<p class=\"has-white-color has-text-color\">Siempre estamos <strong>a la última</strong>, ofreciendo a nuestros lectores y autores los mejores consejos, novedades y recursos para disfrutar y crear literatura de calidad. Desde tips de escritura, recomendaciones de lectura, hasta tendencias editoriales, en Morfeo nos aseguramos de que nunca te pierdas lo más fresco del mundo literario.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"className\":\"has-white-color has-text-color\"} -->\n<p class=\"has-white-color has-text-color\">Ya seas un autor en busca de inspiración, un lector curioso o un amante de las letras, en <strong>Editorial Morfeo</strong> encontrarás tu lugar. ¡Sumérgete con nosotros y despierta tus sueños!</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"http://localhost:8888/contacto/\">Enviar mi obra</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons --></div><figure class=\"wp-block-media-text__media\"><img src=\"http://localhost:8888/wp-content/uploads/2026/03/libros-1-1024x957.png\" alt=\"\" class=\"wp-image-193 size-full\"/></figure></div>\n<!-- /wp:media-text --></div>\n<!-- /wp:group --></div></div>\n<!-- /wp:cover -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"spacing\":{\"padding\":{\"bottom\":\"0px\"}}},\"backgroundColor\":\"ast-global-color-5\",\"layout\":{\"inherit\":false,\"contentSize\":\"1200px\",\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull has-ast-global-color-5-background-color has-background\" style=\"padding-bottom:0px\"><!-- wp:columns {\"verticalAlignment\":\"top\",\"style\":{\"spacing\":{\"blockGap\":\"40px\"}}} -->\n<div class=\"wp-block-columns are-vertically-aligned-top\"><!-- wp:column {\"verticalAlignment\":\"top\",\"style\":{\"spacing\":{\"blockGap\":\"8px\"}}} -->\n<div class=\"wp-block-column is-vertically-aligned-top\"><!-- wp:image {\"id\":134,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:8888/wp-content/themes/astr